    19→function parseDateStr(str: string): Date | null {
    20→  if (!str) return null;
    21→  const [y, m, d] = str.split('-').map(Number);
    22→  if (!y || !m || !d) return null;
    23→  return new Date(y, m - 1, d);
    24→}
