   193→interface LeadListProps {
   194→  leads: LeadReport[];
   195→  onEdit: (lead: LeadReport) => void;
   196→  onDelete: (id: string) => Promise<void>;
   197→  currentUserRole: 'admin' | 'manager';
   198→  currentManagerName: string;
   199→}
   200→
   201→export default function LeadList({
   202→  leads,
   203→  onEdit,
   204→  onDelete,
   205→  currentUserRole,
   206→  currentManagerName,
   207→}: LeadListProps) {
   208→  const [search, setSearch] = useState('');
   209→  const [statusFilter, setStatusFilter] = useState<string>('all');
   210→  const [managerFilter, setManagerFilter] = useState<string>('all');
   211→  const [dateFilter, setDateFilter] = useState<string>(() => todayMsk());
   212→  const [depositFilter, setDepositFilter] = useState<'all' | 'paid' | 'not_paid'>('all');
   213→
   214→  const authorizedLeads = currentUserRole === 'admin'
   215→    ? leads
   216→    : leads.filter(l => l.managerName === currentManagerName);
   217→
   218→  const uniqueManagers = Array.from(new Set(leads.map(l => l.managerName).filter(Boolean)));
   219→
   220→  const getStatusConfig = (status: LeadStatus) => {
