   223→        return { text: 'Запись создана', icon: Calendar, colorClasses: 'bg-indigo-50 border-indigo-200/50 text-indigo-700 font-semibold' };
   224→      case 'rescheduled':
   225→        return { text: 'Запись перенесена', icon: Info, colorClasses: 'bg-amber-50 border-amber-200/50 text-amber-700 font-semibold' };
   226→      case 'showed_up':
   227→        return { text: 'Пришёл', icon: CheckCircle2, colorClasses: 'bg-emerald-50 border-emerald-200/50 text-emerald-700 font-semibold' };
   228→      case 'no_show':
   229→        return { text: 'Не пришёл', icon: XCircle, colorClasses: 'bg-rose-50 border-rose-200/50 text-rose-700' };
   230→      case 'cancelled':
   231→        return { text: 'Отменена', icon: XCircle, colorClasses: 'bg-slate-50 border-slate-200 text-slate-500 font-medium' };
   232→      default:
   233→        return { text: status, icon: Info, colorClasses: 'bg-neutral-50 border-neutral-200 text-neutral-600' };
   234→    }
   235→  };
   236→
   237→  const canDelete = (lead: LeadReport) => {
   238→    if (currentUserRole === 'admin') return true;
   239→    return lead.status !== 'showed_up' && lead.status !== 'no_show';
   240→  };
   241→
   242→  const filteredLeads = authorizedLeads.filter(lead => {
   243→    const term = search.toLowerCase();
   244→    const searchMatch = !search ||
   245→      lead.clientName.toLowerCase().includes(term) ||
   246→      (lead.clientPhone && lead.clientPhone.includes(term)) ||
   247→      (lead.amocrmLeadId && lead.amocrmLeadId.toLowerCase().includes(term));
   248→
   249→    const statusMatch = statusFilter === 'all' || lead.status === statusFilter;
   250→    const managerMatch = currentUserRole !== 'admin' || managerFilter === 'all' || lead.managerName === managerFilter;
   251→
   252→    let dateMatch = true;
   253→    if (dateFilter && lead.bookingDate) {
   254→      dateMatch = String(lead.bookingDate).slice(0, 10) === dateFilter;
   255→    }
   256→
   257→    let depositMatch = true;
   258→    if (depositFilter === 'paid') {
   259→      depositMatch = !!lead.yookassaPaid;
   260→    } else if (depositFilter === 'not_paid') {
   261→      depositMatch = !!lead.amocrmLeadId && !lead.yookassaPaid;
   262→    }
   263→
   264→    return searchMatch && statusMatch && managerMatch && dateMatch && depositMatch;
   265→  });
