   275→  };
   276→
   277→  return (
   278→    <div className="space-y-6">
   279→
   280→      {/* Search & Filters */}
   281→      <div className="spatial-glass rounded-2xl p-5 flex flex-col gap-4 relative transition-all duration-300">
