   291→            onChange={(e) => setSearch(e.target.value)}
   292→            className="w-full pl-11 pr-4 py-3 text-xs bg-white/40 focus:bg-white/80 border border-neutral-150/60 text-neutral-850 placeholder-neutral-400 rounded-xl focus:outline-hidden focus:border-neutral-900 transition-all duration-350 font-semibold shadow-3xs"
   293→          />
   294→        </div>
   295→
   296→        {/* Filters row */}
