   368→              onClick={resetFilters}
   369→              className="text-[9px] font-bold uppercase tracking-widest text-neutral-400 hover:text-neutral-950 transition px-3 py-2 border border-neutral-200/50 rounded-xl bg-white/40 cursor-pointer"
   370→            >
   371→              Сбросить
   372→            </button>
   373→          )}
   374→
   375→        </div>
   376→      </div>
   377→
   378→      {/* Leads List */}
   379→      <div className="space-y-4">
