    23→function formatLastSeen(lastSeenAt: Date | null): string {
    24→  if (!lastSeenAt) return 'Не в сети';
    25→  const diffMs = Date.now() - lastSeenAt.getTime();
    26→  if (diffMs < 0) return 'Не в сети';
